import React, { useMemo } from 'react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend } from 'recharts';
import { TeamStatsData } from '../../types';

interface RankHistoryChartProps {
  data: TeamStatsData[];
}

const RankHistoryChart: React.FC<RankHistoryChartProps> = ({ data }) => {
  // Determine if we have any valid history data
  const hasData = useMemo(() => {
    return data.some(team => team.rankHistory && team.rankHistory.some(rank => rank !== null && rank !== undefined));
  }, [data]);

  const chartData = useMemo(() => {
    if (!hasData) return [];

    // Transform TeamStatsData[] into Recharts data format:
    // [{ name: 'Game 1', TeamA: 1, TeamB: 5 }, { name: 'Game 2', ... }]
    const transformedData: any[] = [];
    const maxWeeks = 10; // As per the columns Game 01 - Game 10

    for (let i = 0; i < maxWeeks; i++) {
      const weekIndex = i + 1;
      const dataPoint: any = { name: `GW ${weekIndex}` };
      let hasWeekData = false;

      data.forEach(team => {
        if (!team.dropped && team.rankHistory && team.rankHistory[i] !== undefined && team.rankHistory[i] !== null) {
          dataPoint[team.teamName] = team.rankHistory[i];
          hasWeekData = true;
        }
      });

      if (hasWeekData) {
        transformedData.push(dataPoint);
      }
    }
    return transformedData;
  }, [data, hasData]);

  // Find max rank to set domain (lowest rank number is best, so max number is worst)
  const maxRank = useMemo(() => {
      let max = 0;
      data.forEach(t => {
          if (!t.dropped && t.rankHistory) {
              t.rankHistory.forEach(r => {
                  if (r && r > max) max = r;
              });
          }
      });
      return max > 0 ? max : 10; // Default to 10 if no data
  }, [data]);

  if (!hasData || chartData.length < 2) {
      return null; // Don't render if not enough data to show a trend
  }

  // Pre-define a color palette if team colors are missing or black
  const fallbackColors = [
    '#EF4444', '#3B82F6', '#10B981', '#F59E0B', '#8B5CF6', '#EC4899', '#06B6D4', '#6366F1'
  ];

  const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload && payload.length) {
      // Sort payload by rank (value) ascending (1 is best)
      const sortedPayload = [...payload].sort((a, b) => a.value - b.value);

      return (
        <div className="bg-dark-card border border-dark-border p-3 rounded-lg shadow-xl bg-opacity-95">
          <p className="font-display font-bold text-light-text mb-2 border-b border-dark-border/50 pb-1">{label}</p>
          <div className="space-y-1">
            {sortedPayload.map((entry: any) => (
              <div key={entry.name} className="flex items-center space-x-2 text-xs md:text-sm">
                <span className="w-2 h-2 rounded-full" style={{ backgroundColor: entry.color }}></span>
                <span className="text-secondary-text font-medium">{entry.name}:</span>
                <span className="text-highlight-gold font-bold">#{entry.value}</span>
              </div>
            ))}
          </div>
        </div>
      );
    }
    return null;
  };

  return (
    <div className="w-full h-[400px] mt-8 mb-8 p-4 bg-dark-bg/20 rounded-xl border border-dark-border/50">
      <h3 className="font-display text-xl font-semibold text-light-text mb-4 pl-2 border-l-4 border-highlight-gold">
        Season Rank Progression
      </h3>
      <ResponsiveContainer width="100%" height="100%">
        <LineChart
          data={chartData}
          margin={{ top: 10, right: 30, left: 0, bottom: 0 }}
        >
          <CartesianGrid strokeDasharray="3 3" stroke="#374151" vertical={false} opacity={0.5} />
          <XAxis 
            dataKey="name" 
            stroke="#9CA3AF" 
            tick={{ fontSize: 12 }} 
            axisLine={{ stroke: '#4B5563' }}
            tickLine={false}
          />
          <YAxis 
            stroke="#9CA3AF" 
            tick={{ fontSize: 12 }} 
            axisLine={{ stroke: '#4B5563' }}
            tickLine={false}
            reversed={true} // Rank 1 at top
            domain={[1, maxRank]}
            allowDecimals={false}
            width={30}
          />
          <Tooltip content={<CustomTooltip />} />
          <Legend wrapperStyle={{ paddingTop: '10px' }} />
          {data.map((team, index) => {
            if (team.dropped) return null; // Don't plot dropped teams
            const lineColor = team.teamColor && team.teamColor !== '#000000' 
                ? team.teamColor 
                : fallbackColors[index % fallbackColors.length];

            return (
              <Line
                key={team.teamName}
                type="monotone"
                dataKey={team.teamName}
                stroke={lineColor}
                strokeWidth={2}
                dot={{ r: 3, strokeWidth: 1, fill: lineColor }}
                activeDot={{ r: 6, strokeWidth: 0 }}
                connectNulls={false} // Don't connect if there's a gap (though data should be continuous until end)
              />
            );
          })}
        </LineChart>
      </ResponsiveContainer>
    </div>
  );
};

export default RankHistoryChart;

import React from 'react';
import { ProcessedSeason, ProcessedGame, TeamStatsData } from '../../types';
